            aOrbiterA = RotL64((aOrbiterA * 14614602561910403893U), 51U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterK) + 4085927978153269932U;
            aOrbiterD = ((aOrbiterD ^ aOrbiterH) ^ 6176195962815240877U) ^ aOrbiterUpdateSaltE[((aIndex + 23U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 16792916528959579875U), 43U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterJ) + 6966742100601433005U;
            aOrbiterE = ((aOrbiterE ^ aOrbiterD) ^ 9920952446921247521U) ^ aOrbiterUpdateSaltB[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 1879821050131820933U), 41U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterI) + 11958734477518336014U;
            aOrbiterK = (((aOrbiterK ^ aOrbiterE) ^ 2058335903640404380U) ^ aOrbiterUpdateSaltC[((aIndex + 20U)) & S_SALT1]) ^ aNonceWordP;
