            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererA = aWandererA + (((RotL64(aScatter, 57U) + RotL64(aOrbiterA, 37U)) + aOrbiterJ) + RotL64(aCarry, 19U));
