            aOrbiterI = ((aWandererE + RotL64(aIngress, 11U)) + 7673376335333251804U) + aOrbiterAssignSaltA[(((31U - aIndex) + 28U)) & S_SALT1];
            aOrbiterD = ((aWandererC + RotL64(aScatter, 27U)) + RotL64(aCarry, 29U)) + 8814147709738503518U;
            aOrbiterK = ((aWandererH + RotL64(aCross, 13U)) + 13451412605350381172U) + aNonceWordF;
            aOrbiterE = ((aWandererK + RotL64(aIngress, 5U)) + 6447870234069609538U) + aNonceWordB;
            aOrbiterC = ((((aWandererA + RotL64(aPrevious, 19U)) + RotL64(aCarry, 5U)) + 13419487997946496825U) + aOrbiterAssignSaltE[((aIndex + 29U)) & S_SALT1]) + aNonceWordO;
            aOrbiterB = (aWandererI + RotL64(aScatter, 51U)) + 5478309847615220345U;
            aOrbiterF = (aWandererF + RotL64(aIngress, 46U)) + 3635184969215610049U;
            aOrbiterG = (aWandererJ + RotL64(aCross, 43U)) + 12527903812035294828U;
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 1684685110885338814U;
            aOrbiterH = ((aOrbiterH ^ aOrbiterJ) ^ 12860354576326835090U) ^ aOrbiterUpdateSaltC[((aIndex + 21U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 12743745087733307255U), 51U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterI) + 9081823570147481835U) + aNonceWordA;
            aOrbiterD = ((aOrbiterD ^ aOrbiterA) ^ 14369321778210049109U) ^ aOrbiterUpdateSaltD[((aIndex + 9U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 17865953349448767035U), 13U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterE) + 11518132079084873250U) + aOrbiterUpdateSaltB[((aIndex + 16U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterK) ^ 11893535026126957389U;
            aOrbiterC = RotL64((aOrbiterC * 15751374986135615095U), 29U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterB) + 7084079180579206226U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterE) ^ 2999676609847603277U;
            aOrbiterJ = RotL64((aOrbiterJ * 14602698397511266403U), 35U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterJ) + 17683445810614029153U;
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 11576460512964896969U;
            aOrbiterF = RotL64((aOrbiterF * 5243651036457051155U), 47U);
